const Header = ({ isLoggedIn, userRole, cerrarSesion }) => {
  return (
    <header style={headerContainer}>
      <div style={logoSection} onClick={() => navigate('/')}>
        <span style={logoWhite}>OFERTAS</span><span style={logoOrange}>APP</span>
      </div>

      <nav style={navLinks}>
        {/* BOTONES PARA CLIENTES O VISITANTES */}
        {(userRole === 'cliente' || !isLoggedIn) && (
          <Link to="/buscar" style={registerLink}>Explorar Ofertas</Link>
        )}

        {!isLoggedIn ? (
          <>
            <Link to="/register" style={registerLink}>Crear cuenta</Link>
            <Link to="/login" style={loginButton}>Ingresar</Link>
          </>
        ) : (
          <>
            {/* BOTONES EXCLUSIVOS PARA VENDEDORES */}
            {userRole === 'vendedor' && (
              <Link to="/dashboard" style={registerLink}>Panel Vendedor</Link>
            )}
            
            <button onClick={cerrarSesion} style={logoutBtn}>Salir</button>
          </>
        )}
      </nav>
    </header>
  );
};
